1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const PROCESSING_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  potion: 40,
11	  amulet: 60,
12	  staff: 80,
13	  rune: 25,
14	};
15	
16	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
17	
18	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
19	
20	const COMPONENT_PREMIUM = 25;
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PREMIUM = 60;
23	
24	const isComponentBlock = (group: Item[]): boolean =>
25	  group.length === COMPONENT_BLOCK_SIZE && itemBasePremium(group[0]) === COMPONENT_PREMIUM;
26	
27	const groupPremium = (group: Item[]): number =>
28	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : group.reduce((sum, item) => sum + itemBasePremium(item), 0);
29	
30	const totalBasePremium = (items: Item[]): number => {
31	  const groups = new Map<string, Item[]>();
32	  for (const item of items) {
33	    const group = groups.get(item.type) ?? [];
34	    group.push(item);
35	    groups.set(item.type, group);
36	  }
37	
38	  let total = 0;
39	  for (const [, group] of groups) {
40	    total += groupPremium(group);
41	  }
42	  return total;
43	};
44	
45	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
46	  items.filter(appliesTo).reduce((sum, item) => sum + itemBasePremium(item) * rate, 0);
47	
48	const conditionalDiscount = (applies: boolean, amount: number, rate: number): number =>
49	  applies ? amount * rate : 0;
50	
51	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
52	  const basePremium = totalBasePremium(items);
53	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
54	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
55	  const itemTotal = basePremium + cursedSurcharge + enchantmentSurcharge;
56	
57	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
58	  const followUpDiscount = conditionalDiscount(contractIndex > 0, basePremium, FOLLOW_UP_DISCOUNT_RATE);
59	  const loyaltyDiscount = conditionalDiscount(customer.yearsWithMHPCO >= 2, basePremium, LOYALTY_DISCOUNT_RATE);
60	  const policyAdjustment = firstInsuranceSurcharge - followUpDiscount - loyaltyDiscount;
61	
62	  return itemTotal + policyAdjustment + PROCESSING_FEE;
63	}
64	
